namespace sv_ff63ffa153d942e7ad05de9cb0369394.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_ff63ffa153d942e7ad05de9cb0369394.Client;

// Runs on WebAssembly. Reads the user info that the server persisted
// via PersistentComponentState so auth state survives the WASM handoff.
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Email),
                new(ClaimTypes.Email, userInfo.Email),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            var identity = new ClaimsIdentity(claims, authenticationType: "Persistent");
            _authState = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
        }
        else
        {
            _authState = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_ff63ffa153d942e7ad05de9cb0369394.Auth;

// Server-side provider that always returns a hardcoded authenticated user.
public sealed class FakeAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state;

    static FakeAuthenticationStateProvider()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "FakeAuth");
        var user = new ClaimsPrincipal(identity);
        _state = Task.FromResult(new AuthenticationState(user));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_ff63ffa153d942e7ad05de9cb0369394.Client;

namespace sv_ff63ffa153d942e7ad05de9cb0369394.Auth;

// Subscribes to PersistentComponentState on the server side and serialises
// the current user's claims so the WebAssembly client can pick them up.
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _underlyingProvider;
    private PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        [FromKeyedServices("FakeAuth")] AuthenticationStateProvider underlyingProvider)
    {
        _persistentState = persistentState;
        _underlyingProvider = underlyingProvider;

        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        return _underlyingProvider.GetAuthenticationStateAsync();
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value
                        ?? principal.FindFirst(ClaimTypes.Name)?.Value;

            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            if (email is not null)
            {
                _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
                {
                    Email = email,
                    Roles = roles,
                });
            }
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <p><strong>Roles:</strong></p>
        <ul>
            @foreach (var role in context.User.FindAll(ClaimTypes.Role))
            {
                <li>@role.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not logged in.</p>
    </NotAuthorized>
</AuthorizeView>

