using Microsoft.AspNetCore.Components.Authorization;
using sv_ff63ffa153d942e7ad05de9cb0369394.Auth;
using sv_ff63ffa153d942e7ad05de9cb0369394.Client.Pages;
using sv_ff63ffa153d942e7ad05de9cb0369394.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddAuthorization();
builder.Services.AddCascadingAuthenticationState();

// Register the fake provider under a key so the persisting wrapper can resolve it.
builder.Services.AddKeyedScoped<AuthenticationStateProvider, FakeAuthenticationStateProvider>("FakeAuth");

// The persisting provider is the primary AuthenticationStateProvider on the server.
// It delegates to FakeAuth and serialises claims for the WASM client.
builder.Services.AddScoped<AuthenticationStateProvider, PersistingAuthenticationStateProvider>();

var app = builder.Build();

using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using sv_ff63ffa153d942e7ad05de9cb0369394.Client;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddSingleton<AuthenticationStateProvider, PersistentAuthenticationStateProvider>();

await builder.Build().RunAsync();

